def T4(N):
    M = 4
    valid = list(range(1 << M))
    def conf_prev(s, prev):
        for r in range(M):
            if s & (1 << r):
                if r-2 >= 0 and (prev & (1 << (r-2))): return True
                if r+2 < M and (prev & (1 << (r+2))): return True
        return False
    def conf_pprev(s, pprev):
        for r in range(M):
            if s & (1 << r):
                if r-1 >= 0 and (pprev & (1 << (r-1))): return True
                if r+1 < M and (pprev & (1 << (r+1))): return True
        return False
    state = {(0, 0): 1}
    out = []
    for col in range(1, N+1):
        new_state = {}
        for (pp, p), cnt in state.items():
            for s in valid:
                if conf_prev(s, p) or conf_pprev(s, pp): continue
                key = (p, s)
                new_state[key] = new_state.get(key, 0) + cnt
        state = new_state
        out.append(sum(state.values()))
    return out
